    NEW.member_group_level := 0;
  end if;

  if coalesce(NEW.district_code::text, '') = '' then
    NEW.district_code := pka_srv_dbattrib.getdefault('sc_mem_m_ucf_member_group','district_code');
  end if;

  if coalesce(NEW.keeping_fingroup::text, '') = '' then
    NEW.keeping_fingroup := pka_srv_dbattrib.getdefault('sc_mem_m_ucf_member_group','keeping_fingroup');
  end if;

  if coalesce(NEW.age_limit::text, '') = '' then
    NEW.age_limit := 0;
  end if;

  if coalesce(NEW.branch_id::text, '') = '' then
    NEW.branch_id := pka_srv_dbattrib.getdefault('sc_mem_m_ucf_member_group','branch_id');
  end if;

  if coalesce(NEW.retire_age::text, '') = '' then
    NEW.retire_age := 0;
  end if;

  if coalesce(NEW.ignor_retire_date::text, '') = '' then
    NEW.ignor_retire_date := pka_srv_dbattrib.getdefault('sc_mem_m_ucf_member_group','ignor_retire_date');
  end if;


  if coalesce(trim(both NEW.mproc_dep_not)::text, '') = '' then NEW.mproc_dep_not :=0;end if;
  if coalesce(NEW.control_id::text, '') = '' then NEW.control_id := 0;end if;
  --salary_group ใช้ออกรายงานส่งไฟล์  เพราะ ส่งไฟล์แยก แต่การเงินโอนรวม
